import{_ as e,c as a,o,U as l}from"./chunks/framework.28b27ef0.js";const f=JSON.parse('{"title":"快捷键","description":"","frontmatter":{},"headers":[],"relativePath":"skill/快捷键.md","filePath":"skill/快捷键.md","lastUpdated":1697384388000}'),c={name:"skill/快捷键.md"},t=l('<h1 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h1><h2 id="vcsode" tabindex="-1">vcsode <a class="header-anchor" href="#vcsode" aria-label="Permalink to &quot;vcsode&quot;">​</a></h2><h3 id="中断再次提醒" tabindex="-1">中断再次提醒 <a class="header-anchor" href="#中断再次提醒" aria-label="Permalink to &quot;中断再次提醒&quot;">​</a></h3><p>document.quer 一半路上,使用 <code>ctrl + i</code> 重新提示</p><h3 id="添加光标" tabindex="-1">添加光标 <a class="header-anchor" href="#添加光标" aria-label="Permalink to &quot;添加光标&quot;">​</a></h3><ul><li>按住 <code>alt</code>, 鼠标左键点击添加</li><li>按 <code>ctrl + alt</code>,在按键盘的 <code>向上/向下</code>,可以使这一列出现光标</li><li>选中一段文字,按<code>shift + alt + i</code>，可以在末尾出现光标</li><li><code>shift + alt</code> 鼠标滑动出现光标</li><li><code>home / end</code> 在当前行出现光标</li><li>使用 <code>ctrl + d</code>，不断加 <code>+d</code>,可以选择多个相似的单词, 使用 <code>ctrl + f2</code>选中所有的相同单词,使用 <code>右箭头</code> 出现在末尾</li><li><code>ctrl + 右箭头</code> 单词末尾</li><li>使用 <code>Home/end</code> 移动到当前行的头部 / 尾部</li></ul><h3 id="取消选中" tabindex="-1">取消选中 <a class="header-anchor" href="#取消选中" aria-label="Permalink to &quot;取消选中&quot;">​</a></h3><ol><li>当使用 <code>ctrl + d</code>时,不需要这个的时候,可以在当前项使用 <code>ctrl + k,ctrl + d</code>取消选中</li><li>使用 <code>ctrl + U</code> 撤销光标处理</li></ol><h3 id="转到定义" tabindex="-1">转到定义 <a class="header-anchor" href="#转到定义" aria-label="Permalink to &quot;转到定义&quot;">​</a></h3><ul><li><code>ctrl + p</code> 输入 <code>@</code> 转到定义</li><li>使用 <code>ctrl + shift + o</code></li></ul><h3 id="切换-tab" tabindex="-1">切换 tab <a class="header-anchor" href="#切换-tab" aria-label="Permalink to &quot;切换 tab&quot;">​</a></h3><ul><li><code>alt + 1</code> 第一个,<code>alt + 0</code>最后一个</li><li><code>ctrl + tab</code> 右边切换,<code>ctrl + shift + tab</code> 左边切换</li></ul><h3 id="转到定义-1" tabindex="-1">转到定义 <a class="header-anchor" href="#转到定义-1" aria-label="Permalink to &quot;转到定义&quot;">​</a></h3><ul><li><code>alt + f12</code> 打开定义</li><li><code>f12</code> 转到定义</li></ul><h3 id="打开文件" tabindex="-1">打开文件 <a class="header-anchor" href="#打开文件" aria-label="Permalink to &quot;打开文件&quot;">​</a></h3><p><code>ctrl + e</code> / <code>ctrl + p</code></p><h3 id="折叠面板" tabindex="-1">折叠面板 <a class="header-anchor" href="#折叠面板" aria-label="Permalink to &quot;折叠面板&quot;">​</a></h3><p><code>ctrl+shift+[</code> 折叠部分 <code>ctrl+shift+]</code> 展开部分</p><p><code>ctrl+k ctrl+0</code> 折叠全部 <code>ctrl+k ctrl+j</code> 展开全部</p><p>自定义 <code>// #region</code> / <code>//# endregion</code></p><h3 id="复制折叠面板" tabindex="-1">复制折叠面板 <a class="header-anchor" href="#复制折叠面板" aria-label="Permalink to &quot;复制折叠面板&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#FFCB6B;">ctrl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">shift</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">+</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">↓</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;"># 直接到末尾处</span></span></code></pre></div><h3 id="缩进" tabindex="-1">缩进 <a class="header-anchor" href="#缩进" aria-label="Permalink to &quot;缩进&quot;">​</a></h3><p><code>ctrl + [</code> 向左移动<br><code>ctrl + ]</code> 向右移动<br><code>ctrl + shift + p</code> 搜索 “缩进”</p><h3 id="格式化代码" tabindex="-1">格式化代码 <a class="header-anchor" href="#格式化代码" aria-label="Permalink to &quot;格式化代码&quot;">​</a></h3><p><code>shift + alt + f</code> 格式化 <code>ctrl + k ctrl + f / ctrl + k + f</code> 局部格式化</p><h3 id="文本选择" tabindex="-1">文本选择 <a class="header-anchor" href="#文本选择" aria-label="Permalink to &quot;文本选择&quot;">​</a></h3><p><code>ctrl + 左箭头/右箭头</code>选中横向文本<br><code>ctrl + 上箭头/下箭头</code>选中纵向文本</p><h3 id="换行" tabindex="-1">换行 <a class="header-anchor" href="#换行" aria-label="Permalink to &quot;换行&quot;">​</a></h3><p><code>ctrl + enter</code> 可以从任意地方换行</p><h3 id="删除" tabindex="-1">删除 <a class="header-anchor" href="#删除" aria-label="Permalink to &quot;删除&quot;">​</a></h3><ul><li><code>ctrl + shift + k</code> 删除一行 如果没有删除可以查看锁钩快捷键</li><li><code>delete</code> 删除后面一个字符</li><li><code>ctrl + delete</code> 删除后面词组</li></ul><h3 id="代码块" tabindex="-1">代码块 <a class="header-anchor" href="#代码块" aria-label="Permalink to &quot;代码块&quot;">​</a></h3><ul><li><code>ctrl + shift + \\</code> 函数括号尾部/头部 进行切换</li><li><code>ctrl + shift + p</code> 选择 <code>选择括号所有内容</code> 选择代码块的内容</li></ul><h3 id="大纲" tabindex="-1">大纲 <a class="header-anchor" href="#大纲" aria-label="Permalink to &quot;大纲&quot;">​</a></h3><p><code>ctrl + shift + p</code> 搜索 <code>大纲</code>，左下角选择<code>排序方式:类别</code></p>',36),d=[t];function r(i,s,h,n,p,u){return o(),a("div",null,d)}const q=e(c,[["render",r]]);export{f as __pageData,q as default};
